f=$(ls -t logs/sessions/*.jsonl | head -1); python3 -c "
import json,sys
for line in open('$f'):
    try: o=json.loads(line)
    except: continue
    m=o.get('message',{})
    r=m.get('role') or o.get('type')
    c=m.get('content')
    if isinstance(c,list):
        for b in c:
            if b.get('type')=='text': print('['+str(r)+']', b['text'][:500])
    elif isinstance(c,str):
        print('['+str(r)+']', c[:500])
" 2>/dev/null | tail -25

echo "=== any battery/charge anywhere in sysfs ==="; grep -rl -i "battery\|charge_now\|capacity" /sys/class/ 2>/dev/null | head; 
echo "=== hwmon sensors ==="; for h in /sys/class/hwmon/hwmon*/; do echo "-- $(cat $h/name 2>/dev/null) ($h)"; done
echo "=== INA / power monitors on i2c (jetson rail telemetry) ==="; ls /sys/bus/i2c/devices/ 2>/dev/null | head -20
